body.script:
//
  // Particle system
  (function() {
    const canvas = document.getElementById('particles-canvas');
    const ctx = canvas.getContext('2d');
    let particles = [];
    let animationId = null;
    let mouseX = -1000;
    let mouseY = -1000;

    function resize() {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    }
    window.addEventListener('resize', resize);
    resize();

    canvas.addEventListener('mousemove', function(e) {
      mouseX = e.clientX;
      mouseY = e.clientY;
    });

    canvas.addEventListener('mouseleave', function() {
      mouseX = -1000;
      mouseY = -1000;
    });

    class Particle {
      constructor() {
        this.x = Math.random() * canvas.width;
        this.y = Math.random() * canvas.height;
        this.size = Math.random() * 1.5 + 0.5;
        this.speedX = (Math.random() - 0.5) * 0.4;
        this.speedY = (Math.random() - 0.5) * 0.4;
        this.opacity = Math.random() * 0.5 + 0.1;
      }

      update() {
        this.x += this.speedX;
        this.y += this.speedY;

        // mouse interaction
        const dx = mouseX - this.x;
        const dy = mouseY - this.y;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < 150) {
          const force = (150 - dist) / 150 * 0.3;
          this.x -= dx / dist * force;
          this.y -= dy / dist * force;
        }

        if (this.x < 0 || this.x > canvas.width) this.speedX *= -1;
        if (this.y < 0 || this.y > canvas.height) this.speedY *= -1;

        // wrap around instead of bounce for smoother effect
        if (this.x < 0) this.x = canvas.width;
        if (this.x > canvas.width) this.x = 0;
        if (this.y < 0) this.y = canvas.height;
        if (this.y > canvas.height) this.y = 0;
      }

      draw() {
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(50, 150, 255, ${this.opacity})`;
        ctx.fill();

        // subtle glow
        if (this.size > 1.2) {
          ctx.shadowColor = 'rgba(50, 150, 255, 0.1)';
          ctx.shadowBlur = 8;
          ctx.fill();
          ctx.shadowBlur = 0;
        }
      }
    }

    function initParticles(count) {
      particles = [];
      for (let i = 0; i < count; i++) {
        particles.push(new Particle());
      }
    }

    function drawLines() {
      for (let i = 0; i < particles.length; i++) {
        for (let j = i + 1; j < particles.length; j++) {
          const dx = particles[i].x - particles[j].x;
          const dy = particles[i].y - particles[j].y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < 120) {
            const opacity = (1 - dist / 120) * 0.08;
            ctx.beginPath();
            ctx.moveTo(particles[i].x, particles[i].y);
            ctx.lineTo(particles[j].x, particles[j].y);
            ctx.strokeStyle = `rgba(50, 150, 255, ${opacity})`;
            ctx.lineWidth = 0.5;
            ctx.stroke();
          }
        }
      }
    }

    function animate() {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      particles.forEach(p => {
        p.update();
        p.draw();
      });

      drawLines();

      animationId = requestAnimationFrame(animate);
    }

    // start with 80 particles
    initParticles(80);
    animate();

    // re-init on resize with appropriate count
    let resizeTimeout;
    window.addEventListener('resize', function() {
      clearTimeout(resizeTimeout);
      resizeTimeout = setTimeout(() => {
        const count = Math.floor((window.innerWidth * window.innerHeight) / 12000);
        initParticles(Math.min(Math.max(count, 50), 120));
      }, 300);
    });
  })();

  // Main scramjet logic
  (function() {
    "use strict";

    const BASE_PATH = location.pathname.replace(/\/[^\/]*$/, "/");
    const swAllowedHostnames = ["localhost", "127.0.0.1"];

    // DOM refs
    const form = document.getElementById("sj-form");
    const address = document.getElementById("sj-address");
    const searchEngine = document.getElementById("sj-search-engine");
    const frameWrapper = document.getElementById("sj-frame-wrapper");
    const frameElement = document.getElementById("sj-frame");
    const frameUrl = document.getElementById("sj-frame-url");
    const error = document.getElementById("sj-error");
    const errorCode = document.getElementById("sj-error-code");
    const openNewTabBtn = document.getElementById("open-new-tab");
    const closeFrameLink = document.getElementById("close-frame-link");
    const wispInput = document.getElementById("wisp-server");

    // helper: search / url
    function search(input, template) {
      try { return new URL(input).toString(); } catch (_) {}
      try {
        const url = new URL("http://" + input);
        if (url.hostname.includes(".")) return url.toString();
      } catch (_) {}
      // easter egg
      if (
        input.includes("zaka") ||
        input.includes("zaka13") ||
        input.includes("zaka's games") ||
        input.includes("ign_zaka13")
      ) {
        alert("Why you searching my name up?");
        alert("lmfao");
      }
      return template.replace("%s", encodeURIComponent(input));
    }

    // register sw
    async function registerSW() {
      if (!navigator.serviceWorker) {
        if (location.protocol !== "https:" && !swAllowedHostnames.includes(location.hostname))
          throw new Error("Service workers cannot be registered without https.");
        throw new Error("Your browser doesn't support service workers.");
      }
      await navigator.serviceWorker.register(BASE_PATH + "sw.js", {
        scope: BASE_PATH,
        updateViaCache: "none",
      });
    }

    // ctrl+shift+z to close frame
    document.addEventListener("keydown", function(e) {
      if (e.ctrlKey && e.shiftKey && e.code === "KeyZ") {
        if (frameWrapper) frameWrapper.style.display = "none";
        if (closeFrameLink) closeFrameLink.style.display = "none";
      }
    });

    // close frame link
    if (closeFrameLink) {
      closeFrameLink.addEventListener("click", function(e) {
        e.preventDefault();
        frameWrapper.style.display = "none";
        closeFrameLink.style.display = "none";
      });
    }

    function showErrorScreen(msg, details) {
      frameWrapper.style.display = "none";
      if (closeFrameLink) closeFrameLink.style.display = "none";
      error.textContent = msg || "something went wrong";
      errorCode.textContent = details || "";
    }

    let controller = null;
    let frame = null;
    let currentWisp = wispInput.value.trim() || "wss://wisp.zaka.qzz.io/wisp/";

    // update wisp on change
    wispInput.addEventListener("change", function() {
      const val = this.value.trim();
      if (val) {
        currentWisp = val;
        // re-init controller with new wisp
        if (controller) {
          controller = null;
          frame = null;
        }
      }
    });

    async function initController() {
      controller = null;
      frame = null;

      const { Controller, config } = window.$scramjetController;

      config.scramjetPath = location.origin + BASE_PATH + "scj/scj.js";
      config.wasmPath = location.origin + BASE_PATH + "scj/scj.wasm";
      config.injectPath = location.origin + BASE_PATH + "controller/controller.inject.js";
      config.prefix = BASE_PATH + "~sj/";

      const transport = new window.LibcurlTransport.LibcurlClient({
        wisp: currentWisp,
      });

      controller = new Controller({
        serviceworker: navigator.serviceWorker.controller,
        transport,
      });
      await controller.wait();

      frame = controller.createFrame(frameElement);
      if (!frame) throw new Error("createFrame returned null — iframe not ready");
    }

    async function navigate(url) {
      if (!url.startsWith("http")) url = "https://" + url;
      if (!frame) await initController();
      await frame.go(url);
      frameWrapper.style.display = "flex";
      if (closeFrameLink) closeFrameLink.style.display = "inline";
      // show url in bottom bar
      try {
        const displayUrl = new URL(url);
        frameUrl.textContent = displayUrl.hostname + displayUrl.pathname;
      } catch (_) {
        frameUrl.textContent = url;
      }
    }

    // new tab (window.open)
    async function newTab() {
      if (address.value.trim() === "") {
        alert("Please type your search/URL into the space below the username field.");
        return;
      }
      const url = search(address.value, searchEngine.value);
      window.open(url, "_blank");
    }

    // form submit
    form.addEventListener("submit", async (event) => {
      event.preventDefault();

      if (address.value.trim() === "") {
        alert("Please type your search/URL into the space below the username field.");
        return;
      }

      const url = search(address.value, searchEngine.value);

      try {
        await registerSW();
      } catch (err) {
        error.textContent = "Failed to register service worker.";
        errorCode.textContent = err.toString();
        throw err;
      }

      if (!navigator.serviceWorker.controller) {
        await new Promise((resolve) =>
          navigator.serviceWorker.addEventListener("controllerchange", resolve, { once: true })
        );
      }

      try {
        await navigate(url);
      } catch (err) {
        showErrorScreen(err.message, err.stack);
      }
    });

    // new tab button
    openNewTabBtn.addEventListener("click", newTab);

    // auto-open from ?goto=
    const goto = new URL(location.href).searchParams.get("goto");
    if (goto) {
      history.replaceState(null, "", location.pathname);
      address.value = goto;
      registerSW()
        .then(() => {
          if (!navigator.serviceWorker.controller) {
            return new Promise((resolve) =>
              navigator.serviceWorker.addEventListener("controllerchange", resolve, { once: true })
            );
          }
        })
        .then(() => navigate(goto))
        .catch((err) => showErrorScreen(err.message, err.stack));
    }

    // expose newTab for inline onclick (backup)
    window.newTab = newTab;

  })();
//

